CREATE TABLE IF NOT EXISTS t_p80382263_mycat_messenger_1.users (id SERIAL PRIMARY KEY, phone VARCHAR(20) UNIQUE NOT NULL, username VARCHAR(50) UNIQUE, name VARCHAR(100) NOT NULL, bio TEXT DEFAULT '', avatar_color VARCHAR(10) DEFAULT '#2e6fdb', avatar_letter VARCHAR(5) DEFAULT '', password_hash VARCHAR(255) NOT NULL, online BOOLEAN DEFAULT false, last_seen TIMESTAMPTZ DEFAULT NOW(), created_at TIMESTAMPTZ DEFAULT NOW())
